import{_ as i,o as a,c as n,a4 as t}from"./chunks/framework.DkKDtR5x.js";const y=JSON.parse('{"title":"Cryptography","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"cryptography.md","filePath":"cryptography.md"}'),r={name:"cryptography.md"};function o(s,e,l,c,d,h){return a(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="cryptography" tabindex="-1">Cryptography <a class="header-anchor" href="#cryptography" aria-label="Permalink to “Cryptography”">​</a></h1><p>These concepts fit under the core software engineering category of Data Security and Information Management.</p><h2 id="📂-taxonomy-breakdown" tabindex="-1">📂 Taxonomy Breakdown <a class="header-anchor" href="#📂-taxonomy-breakdown" aria-label="Permalink to “📂 Taxonomy Breakdown”">​</a></h2><ul><li>Primary Category: Computer Science / Software Engineering</li><li>Sub-Category: Data Security &amp; Cryptography</li><li>Domain: Cyber Security / Data Transmission / System Architecture</li></ul><h2 id="🔍-quick-definitions" tabindex="-1">🔍 Quick Definitions <a class="header-anchor" href="#🔍-quick-definitions" aria-label="Permalink to “🔍 Quick Definitions”">​</a></h2><ul><li>Encoding: Data transformation for system compatibility (Not secure).</li><li>Hashing: One-way data masking for integrity and validation.</li><li>Encryption: Two-way data scrambling for privacy and confidentiality. [1, 2, 3, 4, 5]</li></ul><h2 id="💻-where-you-meet-them-in-software-engineering" tabindex="-1">💻 Where You Meet Them in Software Engineering <a class="header-anchor" href="#💻-where-you-meet-them-in-software-engineering" aria-label="Permalink to “💻 Where You Meet Them in Software Engineering”">​</a></h2><ol><li>Data Engineering &amp; Networking (Encoding)</li></ol><ul><li>Ensures different systems can read data.</li><li>Converts binary data into readable text.</li><li>Examples include Base64, URL encoding, and ASCII. [6, 7, 8]</li></ul><ol><li>Identity &amp; Access Management (Hashing)</li></ol><ul><li>Verifies data integrity without storing secrets.</li><li>Protects user passwords in databases.</li><li>Examples include bcrypt, Argon2, and SHA-256. [9, 10, 11, 12]</li></ul><ol><li>Secure Communications (Encryption)</li></ol><ul><li>Protects sensitive data from prying eyes.</li><li>Requires secret keys to read data.</li><li>Examples include AES, RSA, and HTTPS/TLS. [13, 14, 15, 16]</li></ul><h2 id="encoding-vs-hashing-vs-encryption" tabindex="-1">Encoding vs Hashing vs Encryption <a class="header-anchor" href="#encoding-vs-hashing-vs-encryption" aria-label="Permalink to “Encoding vs Hashing vs Encryption”">​</a></h2><h3 id="encoding" tabindex="-1">Encoding <a class="header-anchor" href="#encoding" aria-label="Permalink to “Encoding”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>what is encoding?</span></span>
<span class="line"><span>&gt;&gt; what%20is%20encoding%3F</span></span></code></pre></div><p>URLs are allowed to have limited number of characters, <code></code> (space) and <code>?</code> are not one of that.<br> This transformation of data to another form for the purpose of storage or transmission is called encoding.<br> Many other options for encoding - binary, hexadecimal, base64, UTF-8</p><blockquote><p>Encoding is reversible, anyone can decode %20 to space (&#39; &#39;) It is about data representation and not security</p></blockquote><p><strong>Other usecases</strong></p><ul><li>color names is css as Hexadecimal instead of rgb</li></ul><h3 id="hashing" tabindex="-1">Hashing <a class="header-anchor" href="#hashing" aria-label="Permalink to “Hashing”">​</a></h3><p>A Process to convert data into another irreversible form by using a Hashing Algorithm.</p><ul><li>Passwords are never stored in DB in plaintext</li><li>They are converted to other form using <code>Hashing</code></li><li>It is impossible to revert from hashed value to plaintext.</li><li>Entered password is hashed again and compared with the stored hashed value.</li><li>Examples : SHA-256, BCrypt, Argon2</li></ul><p>Main Features of Hashing</p><ul><li>Irreversible : Hashing is one-way</li><li>Deterministic : Same input always produces the same hash</li><li>Fixed Length : Output is always of the same size</li></ul><p>Other Usecases</p><ul><li>Store password in DB</li><li>Downloaded file validation - corrupted file will have different hash value</li></ul><h3 id="encryption" tabindex="-1">Encryption <a class="header-anchor" href="#encryption" aria-label="Permalink to “Encryption”">​</a></h3><ul><li>Two way conversion only if user has the key</li><li>otherwise some junk data is presented</li><li>Example : AES, RSA</li><li>Famous example from history - Caesar&#39;s Cipher/Shift Cipher <ul><li>shift each alphabet by fixed position, say 3 (A -&gt; D)</li></ul></li></ul><h2 id="encryption-1" tabindex="-1">Encryption <a class="header-anchor" href="#encryption-1" aria-label="Permalink to “Encryption”">​</a></h2><p>Essentially an art of hiding information</p><ul><li>Hashing (SHA 2):</li><li>Symmetric Encryption - Same key used for encryption and decryption of data (AES)</li><li>Asymmetric Encryption - Private key used for encryption, but public key used for decryption of data (RSA 256)</li></ul><h3 id="sha-2" tabindex="-1">SHA 2 <a class="header-anchor" href="#sha-2" aria-label="Permalink to “SHA 2”">​</a></h3><p>Hashing is a one-way transformation SHA 256 - 256 bits</p><ul><li>same input results in same output everytime</li><li>hashing used when you download software by using SHA 256 checksum</li><li>also used to save passsword in database instead of plain text</li><li></li></ul><h3 id="symmetric-encryption-aes" tabindex="-1">Symmetric Encryption - AES <a class="header-anchor" href="#symmetric-encryption-aes" aria-label="Permalink to “Symmetric Encryption - AES”">​</a></h3><ul><li>components <ul><li>key</li><li>IV (initialization vector) : makes sure every encryption looks different even if same key and message is used, usecase: messaging app in case someone sends same message twice</li><li>Mode : AES works on chunks of data, mode decides how to handle messages longer than 1 block. <ul><li>CBC : Cyber Blockchaining - each block of data mixed with previous block to hide patterns</li><li>EBC : encrypts each block separately, meaning identical plain text equals identical cipher text. Attackers can spot pattern easily so it&#39;s outdated and not used much.</li><li>CTR : used in Network traffic</li><li>GCM : popular for web encryption</li></ul></li><li></li></ul></li></ul>`,37)])])}const u=i(r,[["render",o]]);export{y as __pageData,u as default};
